export enum UserRole {
  ADMIN = 'ADMIN',
  STUDENT = 'STUDENT'
}

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface StudyContext {
  content: string;
  fileName: string;
  updatedAt: Date;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { IAM_SYSTEM_INSTRUCTION } from "../constants";

export async function askIAM(userMessage: string, context: string, chatHistory: { role: 'user' | 'model', parts: { text: string }[] }[] = []) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const fullContext = `
[CONTEXTO DE ESTUDO]
${context || "Nenhum conteúdo foi carregado ainda pelo administrador."}

---
Pergunta do Aluno:
${userMessage}
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...chatHistory,
        { role: 'user', parts: [{ text: fullContext }] }
      ],
      config: {
        systemInstruction: IAM_SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });

    return response.text || "Desculpe, tive um problema ao processar sua resposta.";
  } catch (error) {
    console.error("Erro na API Gemini:", error);
    return "Ocorreu um erro ao conectar com o professor IAM. Verifique sua conexão ou tente novamente mais tarde.";
  }
}

import React from 'react';

interface MarkdownRendererProps {
  content: string;
}

const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ content }) => {
  // Simple markdown-to-html transformation logic for common patterns
  // Bold
  let html = content.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
  // Lists
  html = html.replace(/^\s*[-*+]\s+(.*)$/gm, '<li>$1</li>');
  html = html.replace(/(<li>.*<\/li>)+/g, '<ul class="list-disc ml-5 my-2">$0</ul>');
  // Newlines to breaks (if not in a list)
  html = html.split('\n').map(line => line.trim() ? `<p>${line}</p>` : '').join('');

  return (
    <div 
      className="markdown-body text-slate-800 leading-relaxed"
      dangerouslySetInnerHTML={{ __html: html }}
    />
  );
};

export default MarkdownRenderer;

import React, { useState, useEffect } from 'react';
import { UserRole, StudyContext, Message } from './types';
import AdminPanel from './components/AdminPanel';
import StudentChat from './components/StudentChat';
import { BookOpen, ShieldCheck, GraduationCap, Info } from 'lucide-react';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.STUDENT);
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);
  const [studyContext, setStudyContext] = useState<StudyContext | null>(null);

  // Load context from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('iam_study_context');
    if (saved) {
      setStudyContext(JSON.parse(saved));
    }
  }, []);

  const handleUpdateContext = (newContext: StudyContext) => {
    setStudyContext(newContext);
    localStorage.setItem('iam_study_context', JSON.stringify(newContext));
  };

  const clearContext = () => {
    setStudyContext(null);
    localStorage.removeItem('iam_study_context');
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-emerald-600 p-2 rounded-lg text-white">
              <GraduationCap size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-900 leading-tight">IAM</h1>
              <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wider">Inteligência Artificial Medeiros</p>
            </div>
          </div>

          <nav className="flex items-center gap-4">
            <button
              onClick={() => setRole(UserRole.STUDENT)}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium transition-all ${
                role === UserRole.STUDENT 
                  ? 'bg-emerald-100 text-emerald-700' 
                  : 'text-slate-500 hover:text-slate-800'
              }`}
            >
              <BookOpen size={16} />
              Área do Aluno
            </button>
            <button
              onClick={() => setRole(UserRole.ADMIN)}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium transition-all ${
                role === UserRole.ADMIN 
                  ? 'bg-indigo-100 text-indigo-700' 
                  : 'text-slate-500 hover:text-slate-800'
              }`}
            >
              <ShieldCheck size={16} />
              Administração
            </button>
          </nav>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-5xl mx-auto w-full px-4 py-8">
        {role === UserRole.ADMIN ? (
          <AdminPanel 
            context={studyContext} 
            onUpdate={handleUpdateContext} 
            onClear={clearContext}
            isLoggedIn={isAdminLoggedIn}
            onLoginSuccess={() => setIsAdminLoggedIn(true)}
          />
        ) : (
          <StudentChat studyContext={studyContext?.content || ""} />
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-4">
        <div className="max-w-5xl mx-auto px-4 flex flex-col md:flex-row justify-between items-center gap-4 text-sm text-slate-400">
          <p>&copy; {new Date().getFullYear()} IAM – Inteligência Artificial Medeiros</p>
          <div className="flex items-center gap-1">
            <Info size={14} />
            <span>Educação com responsabilidade e precisão técnica.</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { StudyContext } from '../types';
import { ADMIN_PASSWORD_MOCK } from '../constants';
import { Upload, Trash2, FileText, CheckCircle, AlertCircle, Eye, EyeOff, Loader2 } from 'lucide-react';

interface AdminPanelProps {
  context: StudyContext | null;
  onUpdate: (context: StudyContext) => void;
  onClear: () => void;
  isLoggedIn: boolean;
  onLoginSuccess: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ context, onUpdate, onClear, isLoggedIn, onLoginSuccess }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [manualText, setManualText] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === ADMIN_PASSWORD_MOCK) {
      onLoginSuccess();
      setError('');
    } else {
      setError('Senha incorreta. Acesso negado.');
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);

    try {
      if (file.type === 'application/pdf') {
        // PDF Processing using PDF.js from global scope
        const reader = new FileReader();
        reader.onload = async () => {
          const typedArray = new Uint8Array(reader.result as ArrayBuffer);
          // @ts-ignore
          const pdf = await window.pdfjsLib.getDocument(typedArray).promise;
          let fullText = '';
          for (let i = 1; i <= pdf.numPages; i++) {
            const page = await pdf.getPage(i);
            const textContent = await page.getTextContent();
            fullText += textContent.items.map((item: any) => item.str).join(' ') + '\n';
          }
          onUpdate({
            content: fullText,
            fileName: file.name,
            updatedAt: new Date()
          });
          setIsProcessing(false);
        };
        reader.readAsArrayBuffer(file);
      } else if (file.type === 'text/plain') {
        const reader = new FileReader();
        reader.onload = (re) => {
          onUpdate({
            content: re.target?.result as string,
            fileName: file.name,
            updatedAt: new Date()
          });
          setIsProcessing(false);
        };
        reader.readAsText(file);
      } else {
        alert("Por favor, envie um arquivo PDF ou TXT.");
        setIsProcessing(false);
      }
    } catch (err) {
      console.error("Erro ao ler arquivo:", err);
      alert("Houve um erro ao processar o arquivo.");
      setIsProcessing(false);
    }
  };

  const handleManualSave = () => {
    if (!manualText.trim()) return;
    onUpdate({
      content: manualText,
      fileName: 'Texto Manual',
      updatedAt: new Date()
    });
    setManualText('');
  };

  if (!isLoggedIn) {
    return (
      <div className="max-w-md mx-auto bg-white p-8 rounded-2xl shadow-sm border border-slate-200 mt-12">
        <h2 className="text-2xl font-bold text-slate-800 mb-6 text-center">Acesso Restrito</h2>
        <form onSubmit={handleLogin} className="space-y-4">
          <div className="relative">
            <input
              type={showPassword ? "text" : "password"}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Digite a senha do administrador"
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
            />
            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-3 top-3.5 text-slate-400 hover:text-slate-600"
            >
              {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
          </div>
          {error && <p className="text-red-500 text-sm flex items-center gap-1"><AlertCircle size={14} /> {error}</p>}
          <button
            type="submit"
            className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-xl transition-colors shadow-lg shadow-indigo-200"
          >
            Entrar
          </button>
          <p className="text-[10px] text-slate-400 text-center mt-4 uppercase">Para testes: admin123</p>
        </form>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-indigo-50 border border-indigo-100 p-6 rounded-2xl flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-bold text-indigo-900 mb-1">Configuração de Conteúdo</h2>
          <p className="text-indigo-600 text-sm">Gerencie o material didático que o IAM usará como base.</p>
        </div>
        {context && (
          <button
            onClick={onClear}
            className="flex items-center gap-2 px-4 py-2 bg-white text-red-600 border border-red-100 rounded-xl hover:bg-red-50 transition-colors text-sm font-semibold"
          >
            <Trash2 size={16} />
            Limpar Base
          </button>
        )}
      </div>

      <div className="grid md:grid-cols-2 gap-6">
        {/* Upload Section */}
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col">
          <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
            <Upload size={20} className="text-indigo-600" />
            Upload de Documento
          </h3>
          <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-xl p-8 hover:border-indigo-400 transition-colors cursor-pointer relative group">
            <input
              type="file"
              onChange={handleFileUpload}
              accept=".pdf,.txt"
              className="absolute inset-0 opacity-0 cursor-pointer"
              disabled={isProcessing}
            />
            {isProcessing ? (
              <div className="text-center">
                <Loader2 size={40} className="text-indigo-600 animate-spin mx-auto mb-3" />
                <p className="text-slate-600 font-medium">Extraindo texto do documento...</p>
              </div>
            ) : (
              <div className="text-center group-hover:scale-105 transition-transform">
                <FileText size={48} className="text-slate-300 mx-auto mb-3 group-hover:text-indigo-400" />
                <p className="text-slate-600 font-medium">Clique para selecionar PDF ou TXT</p>
                <p className="text-slate-400 text-xs mt-1">O texto será extraído automaticamente</p>
              </div>
            )}
          </div>
        </div>

        {/* Manual Input Section */}
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col">
          <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
            <FileText size={20} className="text-emerald-600" />
            Inserção Manual
          </h3>
          <textarea
            value={manualText}
            onChange={(e) => setManualText(e.target.value)}
            placeholder="Cole aqui o texto que o IAM deve ensinar..."
            className="flex-1 w-full bg-slate-50 border border-slate-200 rounded-xl p-4 text-slate-700 outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 resize-none transition-all mb-4"
          />
          <button
            onClick={handleManualSave}
            disabled={!manualText.trim()}
            className="w-full bg-emerald-600 hover:bg-emerald-700 disabled:opacity-50 text-white font-bold py-3 rounded-xl transition-colors"
          >
            Salvar Texto Manual
          </button>
        </div>
      </div>

      {/* Current Base Display */}
      {context ? (
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
              <CheckCircle size={20} className="text-emerald-500" />
              Base de Conhecimento Ativa
            </h3>
            <span className="text-xs text-slate-400">
              Última atualização: {context.updatedAt.toLocaleString()}
            </span>
          </div>
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 max-h-60 overflow-y-auto">
            <p className="text-xs font-bold text-emerald-600 uppercase mb-2">Arquivo: {context.fileName}</p>
            <p className="text-sm text-slate-600 whitespace-pre-wrap">{context.content}</p>
          </div>
        </div>
      ) : (
        <div className="bg-amber-50 border border-amber-100 p-6 rounded-2xl flex items-center gap-4">
          <AlertCircle size={24} className="text-amber-500 shrink-0" />
          <div>
            <p className="text-amber-800 font-bold">Nenhum conteúdo carregado!</p>
            <p className="text-amber-600 text-sm">O IAM não terá informações para responder aos alunos até que você forneça uma base.</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useRef, useEffect } from 'react';
import { askIAM } from '../services/geminiService';
import { Message } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { Send, User, Sparkles, AlertTriangle, RefreshCw } from 'lucide-react';

interface StudentChatProps {
  studyContext: string;
}

const StudentChat: React.FC<StudentChatProps> = ({ studyContext }) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      text: "Olá! Sou o **IAM – Inteligência Artificial Medeiros**, seu mentor dedicado. Estou pronto para te ajudar a dominar o conteúdo que estamos estudando. Qual a sua dúvida de hoje?",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    // Prepare history for API
    const history = messages.map(m => ({
      role: m.role,
      parts: [{ text: m.text }]
    }));

    const response = await askIAM(userMessage.text, studyContext, history);

    const modelMessage: Message = {
      id: (Date.now() + 1).toString(),
      role: 'model',
      text: response,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, modelMessage]);
    setIsLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto flex flex-col h-[70vh] bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Header Info */}
      <div className="px-6 py-4 bg-emerald-600 text-white flex items-center justify-between shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-emerald-500 flex items-center justify-center border-2 border-emerald-400 shadow-inner">
            <Sparkles size={20} className="text-emerald-100" />
          </div>
          <div>
            <h3 className="font-bold leading-none">Conversando com IAM</h3>
            <span className="text-[10px] opacity-80 flex items-center gap-1 uppercase tracking-widest mt-1">
              <span className="w-1.5 h-1.5 bg-emerald-200 rounded-full animate-pulse"></span>
              Professor Online
            </span>
          </div>
        </div>
        {!studyContext && (
          <div className="flex items-center gap-1 text-[10px] bg-red-500/30 px-2 py-1 rounded-full text-white animate-bounce">
            <AlertTriangle size={12} />
            CONTEÚDO NÃO DEFINIDO
          </div>
        )}
      </div>

      {/* Messages */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/30"
      >
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in duration-300`}
          >
            <div className={`flex gap-3 max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${
                msg.role === 'user' ? 'bg-indigo-100 text-indigo-600' : 'bg-emerald-100 text-emerald-600'
              }`}>
                {msg.role === 'user' ? <User size={16} /> : <Sparkles size={16} />}
              </div>
              <div className={`p-4 rounded-2xl shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-800 border border-slate-100 rounded-tl-none'
              }`}>
                {msg.role === 'user' ? (
                  <p className="whitespace-pre-wrap leading-relaxed">{msg.text}</p>
                ) : (
                  <MarkdownRenderer content={msg.text} />
                )}
                <span className={`text-[10px] mt-2 block ${msg.role === 'user' ? 'text-indigo-200' : 'text-slate-400'}`}>
                  {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start animate-in fade-in duration-300">
            <div className="flex gap-3 max-w-[85%]">
              <div className="w-8 h-8 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center">
                <RefreshCw size={16} className="animate-spin" />
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 rounded-tl-none">
                <div className="flex gap-1">
                  <span className="w-2 h-2 bg-slate-300 rounded-full animate-bounce"></span>
                  <span className="w-2 h-2 bg-slate-300 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                  <span className="w-2 h-2 bg-slate-300 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-200 shrink-0">
        {!studyContext && (
          <div className="mb-4 p-3 bg-red-50 border border-red-100 rounded-xl flex items-start gap-2">
            <AlertTriangle size={18} className="text-red-500 shrink-0" />
            <p className="text-xs text-red-700 font-medium">O administrador ainda não carregou o conteúdo. O IAM não terá base para ensinar agora.</p>
          </div>
        )}
        <form onSubmit={handleSend} className="relative flex items-center gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isLoading || !studyContext}
            placeholder={studyContext ? "Digite sua dúvida aqui..." : "Aguardando conteúdo..."}
            className="flex-1 bg-slate-100 border-none rounded-2xl px-5 py-4 text-slate-700 outline-none focus:ring-2 focus:ring-emerald-500 transition-all placeholder:text-slate-400 disabled:opacity-50"
          />
          <button
            type="submit"
            disabled={isLoading || !input.trim() || !studyContext}
            className="bg-emerald-600 hover:bg-emerald-700 disabled:opacity-50 disabled:bg-slate-300 text-white p-4 rounded-2xl transition-all shadow-lg shadow-emerald-100 shrink-0"
          >
            <Send size={20} />
          </button>
        </form>
        <p className="text-[10px] text-slate-400 mt-3 text-center">
          Pressione Enter para enviar. O IAM responde apenas com base no material de estudo.
        </p>
      </div>
    </div>
  );
};

export default StudentChat;

import React, { useMemo } from 'react';
import { marked } from 'marked';
import DOMPurify from 'dompurify';

interface MarkdownRendererProps {
  content: string;
}

const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ content }) => {
  const sanitizedHtml = useMemo(() => {
    if (!content) return '';

    // Configura o marked para quebras de linha automáticas
    marked.setOptions({
      breaks: true,
      gfm: true
    });

    const rawHtml = marked.parse(content) as string;
    return DOMPurify.sanitize(rawHtml);
  }, [content]);

  return (
    <div 
      className="prose prose-slate prose-sm md:prose-base text-inherit"
      dangerouslySetInnerHTML={{ __html: sanitizedHtml }}
    />
  );
};

export default MarkdownRenderer;

