      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isLoading]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;

    const userText = input.trim();
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: userText,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    // Prepare history for API (limited to last 10 turns for token efficiency)
    const history = messages.slice(-10).map(m => ({
      role: m.role,
      parts: [{ text: m.text }]
    }));

    const response = await askIAM(userText, studyContext, history);

    const modelMessage: Message = {
      id: (Date.now() + 1).toString(),
      role: 'model',
      text: response,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, modelMessage]);
    setIsLoading(false);
  };

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[75vh] bg-white rounded-3xl shadow-2xl shadow-slate-200/50 border border-slate-200 overflow-hidden transition-all">
      {/* Header Info */}
      <div className="px-6 py-5 bg-gradient-to-r from-emerald-600 to-emerald-500 text-white flex items-center justify-between shrink-0 shadow-md">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-2xl bg-white/20 backdrop-blur-md flex items-center justify-center border border-white/30 shadow-inner group transition-all">
            <GraduationCap size={28} className="text-white group-hover:scale-110 transition-transform" />
          </div>
          <div>
            <h3 className="font-bold text-lg leading-tight tracking-tight">IAM</h3>
            <div className="flex items-center gap-2 mt-0.5">
              <span className="w-2 h-2 bg-emerald-300 rounded-full animate-pulse"></span>
              <span className="text-xs font-medium text-emerald-50 opacity-90 uppercase tracking-widest">Professor Especialista</span>
            </div>
          </div>
        </div>
        {!studyContext && (
          <div className="flex items-center gap-2 text-xs font-bold bg-white/10 px-3 py-1.5 rounded-full border border-white/20 animate-pulse">
            <AlertTriangle size={14} />
            AGUARDANDO CONTEÚDO
          </div>
        )}
      </div>

      {/* Messages */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 space-y-8 bg-[radial-gradient(#e2e8f0_1px,transparent_1px)] [background-size:20px_20px]"
      >
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-500`}
          >
            <div className={`flex gap-4 max-w-[88%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white' 
                  : 'bg-emerald-500 text-white ring-4 ring-emerald-50'
              }`}>
                {msg.role === 'user' ? <User size={20} /> : <Sparkles size={20} />}
              </div>
              <div className={`p-5 rounded-2xl shadow-sm relative group ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-800 border border-slate-100 rounded-tl-none ring-1 ring-slate-200/50'
              }`}>
                {msg.role === 'user' ? (
                  <p className="whitespace-pre-wrap leading-relaxed font-medium">{msg.text}</p>
                ) : (
                  <MarkdownRenderer content={msg.text} />
                )}
                <div className={`absolute -bottom-6 ${msg.role === 'user' ? 'right-0' : 'left-0'} flex items-center gap-2`}>
                   <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">
                    {msg.role === 'user' ? 'Você' : 'IAM'} • {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
                </div>
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start animate-in fade-in duration-300">
            <div className="flex gap-4 max-w-[85%]">
              <div className="w-10 h-10 rounded-xl bg-emerald-500 text-white flex items-center justify-center animate-pulse">
                <RefreshCw size={20} className="animate-spin" />
              </div>
              <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 rounded-tl-none flex items-center gap-3">
                <div className="flex gap-1.5">
                  <span className="w-2.5 h-2.5 bg-emerald-400 rounded-full animate-bounce [animation-duration:0.8s]"></span>
                  <span className="w-2.5 h-2.5 bg-emerald-400 rounded-full animate-bounce [animation-duration:0.8s] [animation-delay:0.15s]"></span>
                  <span className="w-2.5 h-2.5 bg-emerald-400 rounded-full animate-bounce [animation-duration:0.8s] [animation-delay:0.3s]"></span>
                </div>
                <span className="text-xs font-bold text-emerald-600 uppercase tracking-widest">IAM analisando...</span>
              </div>
            </div>
          </div>
