import { GoogleGenAI } from "@google/genai";
import { IAM_SYSTEM_INSTRUCTION } from "../constants";

export async function askIAM(userMessage: string, context: string, chatHistory: { role: 'user' | 'model', parts: { text: string }[] }[] = []) {
  // Initialize GoogleGenAI using process.env.API_KEY directly as per @google/genai coding guidelines
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const fullContext = `
[CONTEXTO DE ESTUDO]
${context || "Nenhum conteúdo foi carregado ainda pelo administrador."}

---
Pergunta do Aluno:
${userMessage}
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...chatHistory,
        { role: 'user', parts: [{ text: fullContext }] }
      ],
      config: {
        systemInstruction: IAM_SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });

    // Access the text property directly from GenerateContentResponse
    return response.text || "Desculpe, tive um problema ao processar sua resposta.";
  } catch (error) {
    console.error("Erro na API Gemini:", error);
    return "Ocorreu um erro ao conectar com o professor IAM. Verifique sua conexão ou tente novamente mais tarde.";
  }
}

