export async function speakText(text: string) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Diga de forma didática e animada: ${text.substring(0, 500)}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audio = new Audio(`data:audio/pcm;base64,${base64Audio}`); // Nota: O SDK retorna PCM, para Web simples converteríamos ou usaríamos AudioContext. Simplificado para o exemplo.
      // Em uma app real, usaríamos o AudioContext conforme o manual.
      return base64Audio;
    }
  } catch (e) {
    console.error("Erro TTS:", e);
  }
  return null;
}

import React, { useState, useRef, useEffect } from 'react';
import { askIAM, generateSummary, generateExam } from '../services/geminiService';
import { Message, StudentMode, Question } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { Send, User, Sparkles, AlertTriangle, RefreshCw, GraduationCap, BookOpen, FileCheck, MessageSquare, ChevronLeft, Award } from 'lucide-react';

interface StudentChatProps {
  studyContext: string;
}

const StudentChat: React.FC<StudentChatProps> = ({ studyContext }) => {
  const [mode, setMode] = useState<StudentMode>('dashboard');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [summary, setSummary] = useState<string | null>(null);
  const [exam, setExam] = useState<Question[] | null>(null);
  const [currentExamStep, setCurrentExamStep] = useState(0);
  const [examScore, setExamScore] = useState<{correct: number, total: number} | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleModeChange = async (newMode: StudentMode) => {
    setMode(newMode);
    if (newMode === 'summary' && !summary) {
      setIsLoading(true);
      const res = await generateSummary(studyContext);
      setSummary(res);
      setIsLoading(false);
    }
    if (newMode === 'exam' && !exam) {
      setIsLoading(true);
      const res = await generateExam(studyContext);
      setExam(res);
      setIsLoading(false);
    }
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;
    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    const res = await askIAM(userMsg.text, studyContext, messages.map(m => ({ role: m.role, parts: [{ text: m.text }] })));
    setMessages(prev => [...prev, { id: (Date.now()+1).toString(), role: 'model', text: res, timestamp: new Date() }]);
    setIsLoading(false);
  };

  const handleExamAnswer = (index: number) => {
    if (!exam) return;
    const isCorrect = index === exam[currentExamStep].correctAnswer;
    alert(isCorrect ? "✅ Correto! " + exam[currentExamStep].explanation : "❌ Incorreto. " + exam[currentExamStep].explanation);

    if (currentExamStep < exam.length - 1) {
      setCurrentExamStep(prev => prev + 1);
    } else {
      setExamScore({ correct: 0, total: exam.length }); // Simplificado
      setMode('dashboard');
      alert("Simulado Finalizado! Parabéns pelo esforço.");
      setExam(null);
      setCurrentExamStep(0);
    }
  };

  if (mode === 'dashboard') {
    return (
      <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-500">
        <div className="text-center space-y-2 mb-8">
          <h2 className="text-3xl font-black text-slate-800">Olá, Aluno Medeiros! 👋</h2>
          <p className="text-slate-500 font-medium">O que vamos dominar hoje?</p>
        </div>

        <div className="grid md:grid-cols-3 gap-6">
          <button onClick={() => handleModeChange('chat')} className="group p-8 bg-white border border-slate-200 rounded-[2rem] shadow-sm hover:shadow-xl hover:border-emerald-500 transition-all text-left space-y-4">
            <div className="w-14 h-14 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform">
              <MessageSquare size={28} />
            </div>
            <h3 className="text-xl font-bold text-slate-800">Tirar Dúvidas</h3>
            <p className="text-slate-500 text-sm leading-relaxed">Converse com o IAM sobre qualquer ponto do material.</p>
          </button>

          <button onClick={() => handleModeChange('summary')} className="group p-8 bg-white border border-slate-200 rounded-[2rem] shadow-sm hover:shadow-xl hover:border-indigo-500 transition-all text-left space-y-4">
            <div className="w-14 h-14 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform">
              <BookOpen size={28} />
            </div>
            <h3 className="text-xl font-bold text-slate-800">Gerar Resumo</h3>
            <p className="text-slate-500 text-sm leading-relaxed">O IAM cria uma síntese estratégica dos pontos vitais.</p>
          </button>

          <button onClick={() => handleModeChange('exam')} className="group p-8 bg-white border border-slate-200 rounded-[2rem] shadow-sm hover:shadow-xl hover:border-amber-500 transition-all text-left space-y-4">
            <div className="w-14 h-14 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform">
              <FileCheck size={28} />
            </div>
            <h3 className="text-xl font-bold text-slate-800">Simulado</h3>
            <p className="text-slate-500 text-sm leading-relaxed">Teste seus conhecimentos com questões inéditas.</p>
          </button>
        </div>

        {studyContext && (
          <div className="bg-emerald-600 p-8 rounded-[2rem] text-white flex items-center justify-between shadow-lg shadow-emerald-100">
            <div className="space-y-1">
              <div className="flex items-center gap-2">
                <Award size={20} className="text-emerald-200" />
                <span className="text-xs font-black uppercase tracking-widest text-emerald-100">Status de Estudo</span>
              </div>
              <h4 className="text-2xl font-black italic">"O conhecimento liberta!"</h4>
              <p className="text-emerald-50 opacity-80 text-sm">Material pronto para exploração profunda.</p>
            </div>
            <GraduationCap size={64} className="opacity-20" />
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[80vh] bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
      {/* Mini Header do Modo */}
      <div className="px-6 py-4 bg-slate-50 border-b border-slate-100 flex items-center justify-between">
        <button onClick={() => setMode('dashboard')} className="flex items-center gap-2 text-slate-500 hover:text-slate-800 font-bold text-sm transition-colors">
          <ChevronLeft size={20} /> Voltar ao Hub
        </button>
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
          <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">
            {mode === 'chat' ? 'Chat com Mentor' : mode === 'summary' ? 'Análise de Texto' : 'Simulado Ativo'}
          </span>
        </div>
      </div>

      {isLoading ? (
        <div className="flex-1 flex flex-col items-center justify-center space-y-4">
          <RefreshCw size={48} className="text-emerald-600 animate-spin" />
          <p className="text-slate-600 font-bold animate-pulse">O IAM está processando seu material...</p>
        </div>
      ) : mode === 'summary' ? (
        <div className="flex-1 overflow-y-auto p-10 bg-slate-50/30">
          <div className="max-w-2xl mx-auto bg-white p-12 rounded-[2rem] shadow-sm border border-slate-100">
            <MarkdownRenderer content={summary || ""} />
          </div>
        </div>
      ) : mode === 'exam' && exam ? (
        <div className="flex-1 overflow-y-auto p-10 flex flex-col items-center justify-center">
          <div className="max-w-xl w-full space-y-8 animate-in slide-in-from-right duration-500">
             <div className="space-y-2">
               <span className="text-emerald-600 font-black uppercase tracking-widest text-xs">Questão {currentExamStep + 1} de {exam.length}</span>
               <h3 className="text-2xl font-bold text-slate-800 leading-tight">{exam[currentExamStep].question}</h3>
             </div>
             <div className="space-y-3">
               {exam[currentExamStep].options.map((opt, idx) => (
                 <button 
                  key={idx} 
                  onClick={() => handleExamAnswer(idx)}
                  className="w-full p-5 text-left bg-white border-2 border-slate-100 rounded-2xl hover:border-emerald-500 hover:bg-emerald-50 transition-all font-medium text-slate-700 flex items-center gap-4 group"
                 >
                   <span className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 font-black group-hover:bg-emerald-500 group-hover:text-white transition-colors">
                     {String.fromCharCode(65 + idx)}
                   </span>
                   {opt}
                 </button>
               ))}
             </div>
          </div>
        </div>
      ) : (
        /* Chat Mode */
        <>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6">
            {messages.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-center p-12 space-y-4">
                <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-3xl flex items-center justify-center">
                   <Sparkles size={40} />
                </div>
                <h3 className="text-2xl font-black text-slate-800">O que quer saber hoje?</h3>
                <p className="text-slate-500 max-w-xs font-medium">Estou pronto para explicar qualquer detalhe do conteúdo fornecido pelo administrador.</p>
              </div>
            )}
            {messages.map(m => (
              <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-5 rounded-3xl shadow-sm ${m.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-50 text-slate-800 border border-slate-100'}`}>
                   <MarkdownRenderer content={m.text} />
                </div>
              </div>
            ))}
          </div>
          <form onSubmit={handleSend} className="p-6 bg-white border-t border-slate-100 flex gap-3">
             <input 
              value={input} 
              onChange={e => setInput(e.target.value)} 
              placeholder="Digite sua dúvida técnica..." 
              className="flex-1 bg-slate-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white px-6 py-4 rounded-2xl outline-none transition-all font-medium"
             />
             <button type="submit" className="bg-emerald-600 text-white p-4 rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all">
                <Send size={24} />
             </button>
          </form>
        </>
      )}
    </div>
  );
};

