    });
    const text = response.text.trim();
    return JSON.parse(text);
  } catch (error) {
    console.error(error);
    return null;
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { askIAM, generateSummary, generateExam } from '../services/geminiService';
import { Message, StudentMode, Question } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { Send, User, Sparkles, AlertTriangle, RefreshCw, GraduationCap, BookOpen, FileCheck, MessageSquare, ChevronLeft, Award, Search, BrainCircuit } from 'lucide-react';

interface StudentChatProps {
  studyContext: string;
}

const StudentChat: React.FC<StudentChatProps> = ({ studyContext }) => {
  const [mode, setMode] = useState<StudentMode>('dashboard');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [topicRequest, setTopicRequest] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [summary, setSummary] = useState<string | null>(null);
  const [exam, setExam] = useState<Question[] | null>(null);
  const [currentExamStep, setCurrentExamStep] = useState(0);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const startSummary = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topicRequest.trim()) return;
    setIsLoading(true);
    const res = await generateSummary(studyContext, topicRequest);
    setSummary(res);
    setIsLoading(false);
  };

  const startExam = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topicRequest.trim()) return;
    setIsLoading(true);
    const res = await generateExam(studyContext, topicRequest);
    if (res) {
      setExam(res);
    } else {
      alert("Não consegui gerar questões sobre esse tópico no momento.");
    }
    setIsLoading(false);
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;
    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    const res = await askIAM(userMsg.text, studyContext, messages.map(m => ({ role: m.role, parts: [{ text: m.text }] })));
    setMessages(prev => [...prev, { id: (Date.now()+1).toString(), role: 'model', text: res, timestamp: new Date() }]);
    setIsLoading(false);
  };

  const handleExamAnswer = (index: number) => {
    if (!exam) return;
    const isCorrect = index === exam[currentExamStep].correctAnswer;
    alert(isCorrect ? "✅ Correto! " + exam[currentExamStep].explanation : "❌ Incorreto. " + exam[currentExamStep].explanation);

    if (currentExamStep < exam.length - 1) {
      setCurrentExamStep(prev => prev + 1);
    } else {
      setMode('dashboard');
      alert("Simulado Finalizado! Continue estudando.");
      setExam(null);
      setCurrentExamStep(0);
      setTopicRequest('');
    }
  };

  const LoadingScreen = () => (
    <div className="flex-1 flex flex-col items-center justify-center space-y-8 p-12 text-center animate-in fade-in duration-700">
      <div className="relative">
        <div className="absolute inset-0 bg-emerald-400/20 rounded-full blur-3xl animate-pulse"></div>
        <div className="relative w-32 h-32 bg-white rounded-full flex items-center justify-center shadow-2xl border border-emerald-100">
          <BrainCircuit size={64} className="text-emerald-600 animate-[spin_4s_linear_infinite]" />
        </div>
        <div className="absolute -top-2 -right-2 w-8 h-8 bg-emerald-500 rounded-lg flex items-center justify-center animate-bounce">
          <Sparkles size={16} className="text-white" />
        </div>
      </div>
      <div className="space-y-3">
        <h3 className="text-2xl font-black text-slate-800">IAM Processando...</h3>
        <p className="text-slate-500 font-medium max-w-xs mx-auto">Analisando sua base de conhecimento para entregar o melhor conteúdo.</p>
      </div>
      <div className="flex gap-2">
        <span className="w-3 h-3 bg-emerald-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
        <span className="w-3 h-3 bg-emerald-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
        <span className="w-3 h-3 bg-emerald-500 rounded-full animate-bounce"></span>
      </div>
    </div>
  );

  if (mode === 'dashboard') {
    return (
      <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 px-4">
        <div className="text-center space-y-3 mb-10">
          <div className="inline-block px-4 py-1.5 bg-emerald-100 text-emerald-700 rounded-full text-xs font-black uppercase tracking-widest mb-4">Plataforma Medeiros</div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight">Área do Aluno</h2>
          <p className="text-slate-500 text-lg font-medium">O que vamos dominar no conteúdo hoje?</p>
        </div>

        <div className="grid md:grid-cols-3 gap-8">
          <button onClick={() => setMode('chat')} className="group p-10 bg-white border-2 border-slate-100 rounded-[3rem] shadow-sm hover:shadow-2xl hover:border-emerald-500 transition-all text-left space-y-6">
            <div className="w-16 h-16 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center group-hover:rotate-12 transition-transform">
              <MessageSquare size={32} />
            </div>
            <div>
              <h3 className="text-2xl font-black text-slate-800">Mentor IAM</h3>
              <p className="text-slate-500 text-sm leading-relaxed mt-2">Dúvidas rápidas e explicações detalhadas por chat.</p>
            </div>
          </button>

          <button onClick={() => setMode('summary')} className="group p-10 bg-white border-2 border-slate-100 rounded-[3rem] shadow-sm hover:shadow-2xl hover:border-indigo-500 transition-all text-left space-y-6">
            <div className="w-16 h-16 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center group-hover:rotate-12 transition-transform">
              <BookOpen size={32} />
            </div>
            <div>
              <h3 className="text-2xl font-black text-slate-800">Pedir Resumo</h3>
              <p className="text-slate-500 text-sm leading-relaxed mt-2">Você escolhe a matéria e o IAM sintetiza o essencial.</p>
            </div>
          </button>

          <button onClick={() => setMode('exam')} className="group p-10 bg-white border-2 border-slate-100 rounded-[3rem] shadow-sm hover:shadow-2xl hover:border-amber-500 transition-all text-left space-y-6">
            <div className="w-16 h-16 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center group-hover:rotate-12 transition-transform">
              <FileCheck size={32} />
            </div>
            <div>
              <h3 className="text-2xl font-black text-slate-800">Simulado Focado</h3>
              <p className="text-slate-500 text-sm leading-relaxed mt-2">Teste seus conhecimentos em tópicos específicos.</p>
            </div>
          </button>
        </div>

        {studyContext && (
          <div className="bg-gradient-to-r from-emerald-600 to-emerald-500 p-10 rounded-[3rem] text-white flex flex-col md:flex-row items-center justify-between shadow-2xl shadow-emerald-200 gap-8 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10">
              <GraduationCap size={160} />
            </div>
            <div className="space-y-4 relative z-10 text-center md:text-left">
              <div className="flex items-center gap-3 justify-center md:justify-start">
                <Award size={24} className="text-emerald-200" />
                <span className="text-xs font-black uppercase tracking-[0.2em] text-emerald-100">Pronto para aprender</span>
              </div>
              <h4 className="text-3xl font-black italic max-w-lg leading-tight">"O único erro é desistir de aprender."</h4>
              <p className="text-emerald-50 opacity-90 font-medium">Conteúdo pedagógico processado e disponível para o IAM.</p>
            </div>
            <button onClick={() => setMode('chat')} className="bg-white text-emerald-600 px-8 py-4 rounded-2xl font-black shadow-lg hover:scale-105 transition-transform z-10 whitespace-nowrap">
              Começar agora
            </button>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto flex flex-col h-[82vh] bg-white rounded-[3rem] shadow-2xl border border-slate-100 overflow-hidden relative">
      {/* Header Fixo */}
      <div className="px-8 py-5 bg-slate-50 border-b border-slate-100 flex items-center justify-between z-20">
        <button onClick={() => { setMode('dashboard'); setSummary(null); setExam(null); setTopicRequest(''); }} className="flex items-center gap-2 text-slate-500 hover:text-slate-900 font-black text-xs uppercase tracking-widest transition-all group">
          <ChevronLeft size={20} className="group-hover:-translate-x-1 transition-transform" /> Voltar ao Hub
        </button>
        <div className="flex items-center gap-3">
          <div className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
          <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">
            {mode === 'chat' ? 'Modo Mentor' : mode === 'summary' ? 'Gerador de Resumo' : 'Central de Simulado'}
          </span>
        </div>
      </div>

      {isLoading ? (
        <LoadingScreen />
      ) : mode === 'summary' && !summary ? (
        /* Solicitação de Resumo */
        <div className="flex-1 flex flex-col items-center justify-center p-12 text-center space-y-8 animate-in zoom-in-95 duration-500">
          <div className="w-24 h-24 bg-indigo-100 text-indigo-600 rounded-[2rem] flex items-center justify-center">
            <BookOpen size={48} />
