          </div>
          <form onSubmit={startSummary} className="w-full max-w-md relative group">
            <input 
              value={topicRequest}
              onChange={e => setTopicRequest(e.target.value)}
              placeholder="Ex: Primeiros Socorros, NR-10, APH..."
              className="w-full bg-slate-50 border-3 border-slate-100 rounded-2xl px-6 py-5 text-lg font-bold outline-none focus:border-indigo-500 focus:bg-white transition-all pr-16"
            />
