          </form>
        </div>
      ) : mode === 'exam' && !exam ? (
        /* Solicitação de Simulado */
        <div className="flex-1 flex flex-col items-center justify-center p-12 text-center space-y-8 animate-in zoom-in-95 duration-500">
          <div className="w-24 h-24 bg-amber-100 text-amber-600 rounded-[2rem] flex items-center justify-center">
            <FileCheck size={48} />
