          <div className="max-w-xl w-full space-y-10 animate-in slide-in-from-right-4 duration-500">
             <div className="space-y-4">
               <div className="flex justify-between items-center">
                <span className="text-emerald-600 font-black uppercase tracking-widest text-xs bg-emerald-50 px-3 py-1 rounded-full">Questão {currentExamStep + 1} / {exam.length}</span>
