                   <span className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 font-black group-hover:bg-emerald-500 group-hover:text-white transition-colors shrink-0">
                     {String.fromCharCode(65 + idx)}
