                  <h3 className="text-3xl font-black text-slate-900">Mentor Educacional IAM</h3>
                  <p className="text-slate-500 max-w-sm font-medium text-lg leading-relaxed">Estou conectado à sua base de estudo. O que você gostaria que eu explicasse agora?</p>
                </div>
                <div className="flex gap-2 flex-wrap justify-center">
                  {['Resuma a parte técnica', 'Crie um exemplo prático', 'Explique o capítulo 1'].map(t => (
                    <button key={t} onClick={() => setInput(t)} className="px-4 py-2 bg-white border border-slate-200 rounded-full text-xs font-bold text-slate-500 hover:border-emerald-500 hover:text-emerald-600 transition-all">
                      {t}
                    </button>
                  ))}
                </div>
              </div>
            )}
            {messages.map(m => (
              <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[85%] p-6 rounded-[2rem] shadow-sm relative group ${
                  m.role === 'user' 
                    ? 'bg-emerald-600 text-white rounded-tr-none' 
                    : 'bg-white text-slate-800 border border-slate-100 rounded-tl-none ring-1 ring-slate-200/50'
                }`}>
                   <MarkdownRenderer content={m.text} />
                   <span className={`text-[10px] font-black uppercase opacity-40 mt-3 block ${m.role === 'user' ? 'text-white' : 'text-slate-500'}`}>
                    {m.role === 'user' ? 'Você' : 'Professor IAM'}
                   </span>
                </div>
              </div>
            ))}
          </div>
          <form onSubmit={handleSend} className="p-8 bg-white border-t border-slate-100 flex gap-4 items-center">
             <div className="flex-1 relative group">
                <input 
                  value={input} 
                  onChange={e => setInput(e.target.value)} 
                  placeholder="Sua dúvida pedagógica aqui..." 
                  className="w-full bg-slate-50 border-3 border-transparent focus:border-emerald-500 focus:bg-white px-8 py-5 rounded-[2rem] outline-none transition-all font-bold text-slate-800"
                />
             </div>
             <button type="submit" disabled={!input.trim()} className="bg-emerald-600 text-white p-5 rounded-[1.5rem] shadow-2xl shadow-emerald-200 hover:scale-105 hover:bg-emerald-700 active:scale-95 disabled:bg-slate-200 disabled:shadow-none transition-all">
                <Send size={28} />
             </button>
          </form>
        </>
      )}
    </div>
  );
};

