          <h2 className="text-5xl font-black text-slate-900 tracking-tighter">
            I<span className="text-emerald-500">.</span>AM Expert
          </h2>
          <p className="text-slate-500 text-xl font-medium max-w-lg mx-auto leading-relaxed">Sua inteligência pedagógica personalizada para dominar qualquer conteúdo.</p>
        </div>

        <div className="grid md:grid-cols-3 gap-8">
          <button onClick={() => setMode('chat')} className="group p-10 bg-white border-2 border-slate-100 rounded-[3rem] shadow-sm hover:shadow-2xl hover:border-emerald-500 hover:-translate-y-2 transition-all text-left space-y-6">
            <div className="w-16 h-16 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform">
              <MessageSquare size={32} />
            </div>
            <div>
              <h3 className="text-2xl font-black text-slate-800 tracking-tight">Mentor Direto</h3>
              <p className="text-slate-500 text-sm leading-relaxed mt-2">Dúvidas, teorias e aplicações práticas em tempo real.</p>
            </div>
          </button>

          <button onClick={() => setMode('summary')} className="group p-10 bg-white border-2 border-slate-100 rounded-[3rem] shadow-sm hover:shadow-2xl hover:border-indigo-500 hover:-translate-y-2 transition-all text-left space-y-6">
            <div className="w-16 h-16 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform">
