                  onClick={() => handleExamAnswer(idx)}
                  className="w-full p-8 text-left bg-white border-2 border-slate-100 rounded-[2.5rem] hover:border-emerald-500 hover:bg-emerald-50 hover:translate-x-3 transition-all font-bold text-slate-800 flex items-center gap-6 group shadow-sm"
