      ) : (
        /* Chat Mode */
        <>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-10 space-y-10 bg-[radial-gradient(#e2e8f0_1px,transparent_1px)] [background-size:24px_24px]">
            {messages.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-center p-12 space-y-8">
                <div className="relative">
                  <div className="absolute inset-0 bg-emerald-500 blur-3xl opacity-10 animate-pulse"></div>
                  <div className="relative w-32 h-32 bg-white text-emerald-600 rounded-[3rem] flex items-center justify-center shadow-3xl border border-emerald-50">
                     <BrainCircuit size={64} className="opacity-80" />
                     <Sparkles size={24} className="absolute top-2 right-2 text-emerald-400 animate-bounce" />
                  </div>
                </div>
                <div className="space-y-4 max-w-sm">
                  <h3 className="text-4xl font-black text-slate-900 tracking-tighter">I<span className="text-emerald-500">.</span>AM Online</h3>
                  <p className="text-slate-500 font-medium text-lg leading-relaxed">
                    Eu estou aqui... <span className="text-emerald-600 font-bold">para te ajudar</span>. Pergunte qualquer coisa sobre o material.
                  </p>
                </div>
              </div>
            )}
            {messages.map(m => (
              <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-4 duration-300`}>
                <div className={`max-w-[85%] p-8 rounded-[3rem] shadow-xl relative group ${
                  m.role === 'user' 
                    ? 'bg-gradient-to-br from-emerald-600 to-emerald-700 text-white rounded-tr-none' 
                    : 'bg-white text-slate-800 border border-slate-100 rounded-tl-none ring-1 ring-slate-200/50'
                }`}>
                   <MarkdownRenderer content={m.text} />
                   <div className={`flex items-center gap-2 mt-4 opacity-40 ${m.role === 'user' ? 'text-white' : 'text-slate-400'}`}>
                      <span className="text-[10px] font-black uppercase tracking-widest">
                        {m.role === 'user' ? 'Você' : 'I.AM Mentor'}
                      </span>
                   </div>
                </div>
              </div>
            ))}
          </div>
          <form onSubmit={handleSend} className="p-10 bg-white border-t border-slate-100 flex gap-4 items-center relative z-20">
             <div className="flex-1 relative group">
                <input 
                  value={input} 
                  onChange={e => setInput(e.target.value)} 
                  placeholder="Envie sua mensagem para o I.AM..." 
                  className="w-full bg-slate-50 border-3 border-transparent focus:border-emerald-500 focus:bg-white px-10 py-6 rounded-[2.5rem] outline-none transition-all font-bold text-slate-800 text-lg shadow-inner"
                />
             </div>
             <button type="submit" disabled={!input.trim()} className="bg-slate-900 text-white p-6 rounded-[2rem] shadow-2xl hover:scale-105 hover:bg-black active:scale-95 disabled:bg-slate-200 disabled:shadow-none transition-all">
                <Send size={32} />
             </button>
          </form>
        </>
      )}
    </div>
  );
};

