export default App;

import React, { useState, useRef, useEffect } from 'react';
import { askIAM, generateSummary, generateExam } from '../services/geminiService';
import { Message, StudentMode, Question } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { Send, User, Sparkles, AlertTriangle, RefreshCw, GraduationCap, BookOpen, FileCheck, MessageSquare, ChevronLeft, Award, Search, BrainCircuit } from 'lucide-react';

interface StudentChatProps {
  studyContext: string;
}

const StudentChat: React.FC<StudentChatProps> = ({ studyContext }) => {
  const [mode, setMode] = useState<StudentMode>('dashboard');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [topicRequest, setTopicRequest] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [summary, setSummary] = useState<string | null>(null);
  const [exam, setExam] = useState<Question[] | null>(null);
  const [currentExamStep, setCurrentExamStep] = useState(0);

  const isEmbed = new URLSearchParams(window.location.search).get('embed') === 'true';
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const startSummary = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topicRequest.trim()) return;
    setIsLoading(true);
    const res = await generateSummary(studyContext, topicRequest);
    setSummary(res);
    setIsLoading(false);
  };

  const startExam = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topicRequest.trim()) return;
    setIsLoading(true);
    const res = await generateExam(studyContext, topicRequest);
    if (res) {
      setExam(res);
    } else {
      alert("Não consegui gerar questões sobre esse tópico no momento.");
    }
    setIsLoading(false);
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;
    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    const res = await askIAM(userMsg.text, studyContext, messages.map(m => ({ role: m.role, parts: [{ text: m.text }] })));
    setMessages(prev => [...prev, { id: (Date.now()+1).toString(), role: 'model', text: res, timestamp: new Date() }]);
    setIsLoading(false);
  };

  const handleExamAnswer = (index: number) => {
    if (!exam) return;
    const isCorrect = index === exam[currentExamStep].correctAnswer;
    alert(isCorrect ? "✅ Correto! " + exam[currentExamStep].explanation : "❌ Incorreto. " + exam[currentExamStep].explanation);

    if (currentExamStep < exam.length - 1) {
      setCurrentExamStep(prev => prev + 1);
    } else {
      setMode('dashboard');
      alert("Simulado Finalizado! Continue estudando.");
      setExam(null);
      setCurrentExamStep(0);
      setTopicRequest('');
    }
  };

  const LoadingScreen = () => (
    <div className="flex-1 flex flex-col items-center justify-center space-y-8 p-12 text-center animate-in fade-in duration-700">
      <div className="relative">
        <div className="absolute inset-0 bg-emerald-400/20 rounded-full blur-3xl animate-pulse"></div>
        <div className="relative w-24 h-24 bg-white rounded-full flex items-center justify-center shadow-2xl border border-emerald-100">
          <BrainCircuit size={48} className="text-emerald-600 animate-[spin_4s_linear_infinite]" />
        </div>
        <div className="absolute -top-1 -right-1 w-6 h-6 bg-emerald-500 rounded-lg flex items-center justify-center animate-bounce">
          <Sparkles size={12} className="text-white" />
        </div>
      </div>
      <div className="space-y-3">
        <h3 className="text-2xl font-black text-slate-800">I<span className="text-emerald-500">.</span>AM está processando...</h3>
        <p className="text-slate-500 text-sm font-medium max-w-xs mx-auto leading-relaxed">Sincronizando com o material de estudo para te responder da melhor forma.</p>
      </div>
      <div className="flex gap-2">
        <span className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
        <span className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
        <span className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-bounce"></span>
      </div>
    </div>
  );

  if (mode === 'dashboard') {
    return (
      <div className={`max-w-4xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500 px-4 ${isEmbed ? 'py-4' : ''}`}>
