              </div>
            ))}
          </div>
          <form onSubmit={handleSend} className="p-8 bg-white border-t border-slate-100 flex gap-4 items-center relative z-20">
             <div className="flex-1 relative group">
                <input 
                  value={input} 
                  onChange={e => setInput(e.target.value)} 
