                  className="w-full bg-slate-50 border-3 border-transparent focus:border-emerald-500 focus:bg-white px-8 py-5 rounded-[2rem] outline-none transition-all font-bold text-slate-800 text-base shadow-inner"
                />
             </div>
             <button type="submit" disabled={!input.trim()} className="bg-slate-900 text-white p-5 rounded-[1.5rem] shadow-2xl hover:scale-105 hover:bg-black active:scale-95 disabled:bg-slate-200 disabled:shadow-none transition-all">
                <Send size={24} />
             </button>
          </form>
        </>
      )}
    </div>
  );
};

