import React, { useState, useRef, useEffect } from 'react';
import { askIAM, generateSummary, generateExam } from '../services/geminiService';
import { Message, StudentMode, Question } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { Send, User, Sparkles, AlertTriangle, RefreshCw, GraduationCap, BookOpen, FileCheck, MessageSquare, ChevronLeft, Award, Search, BrainCircuit } from 'lucide-react';

interface StudentChatProps {
  studyContext: string;
}

const StudentChat: React.FC<StudentChatProps> = ({ studyContext }) => {
  const [mode, setMode] = useState<StudentMode>('dashboard');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [topicRequest, setTopicRequest] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [summary, setSummary] = useState<string | null>(null);
  const [exam, setExam] = useState<Question[] | null>(null);
  const [currentExamStep, setCurrentExamStep] = useState(0);

  const isEmbed = new URLSearchParams(window.location.search).get('embed') === 'true';
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const startSummary = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topicRequest.trim()) return;
    setIsLoading(true);
    const res = await generateSummary(studyContext, topicRequest);
    setSummary(res);
    setIsLoading(false);
  };

  const startExam = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topicRequest.trim()) return;
    setIsLoading(true);
    const res = await generateExam(studyContext, topicRequest);
    if (res) {
      setExam(res);
    } else {
      alert("Não consegui gerar questões sobre esse tópico no momento.");
    }
    setIsLoading(false);
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;
    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);
    const res = await askIAM(userMsg.text, studyContext, messages.map(m => ({ role: m.role, parts: [{ text: m.text }] })));
    setMessages(prev => [...prev, { id: (Date.now()+1).toString(), role: 'model', text: res, timestamp: new Date() }]);
    setIsLoading(false);
  };

  const handleExamAnswer = (index: number) => {
    if (!exam) return;
    const isCorrect = index === exam[currentExamStep].correctAnswer;
    alert(isCorrect ? "✅ Correto! " + exam[currentExamStep].explanation : "❌ Incorreto. " + exam[currentExamStep].explanation);

    if (currentExamStep < exam.length - 1) {
      setCurrentExamStep(prev => prev + 1);
    } else {
      setMode('dashboard');
      alert("Simulado Finalizado! Continue estudando.");
      setExam(null);
      setCurrentExamStep(0);
      setTopicRequest('');
    }
  };

  const LoadingScreen = () => (
    <div className="flex-1 flex flex-col items-center justify-center space-y-8 p-12 text-center animate-in fade-in duration-700">
      <div className="relative">
        <div className="absolute inset-0 bg-emerald-400/20 rounded-full blur-3xl animate-pulse"></div>
        <div className="relative w-24 h-24 bg-white rounded-full flex items-center justify-center shadow-2xl border border-emerald-100">
          <BrainCircuit size={48} className="text-emerald-600 animate-[spin_4s_linear_infinite]" />
        </div>
        <div className="absolute -top-1 -right-1 w-6 h-6 bg-emerald-500 rounded-lg flex items-center justify-center animate-bounce">
          <Sparkles size={12} className="text-white" />
        </div>
      </div>
      <div className="space-y-3">
        <h3 className="text-2xl font-black text-slate-800 tracking-tight">I<span className="text-emerald-500">.</span>AM carregando...</h3>
        <p className="text-slate-500 text-sm font-medium max-w-xs mx-auto leading-relaxed italic">Sincronizando com a base de conhecimento.</p>
      </div>
      <div className="flex gap-2">
        <span className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
        <span className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
        <span className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-bounce"></span>
      </div>
    </div>
  );

  if (mode === 'dashboard') {
    return (
      <div className={`max-w-4xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500 px-4 ${isEmbed ? 'py-4' : ''}`}>
        <div className="text-center space-y-4 mb-8">
          <div className="inline-flex items-center gap-2 px-3 py-1 bg-slate-900 text-white rounded-full text-[9px] font-black uppercase tracking-[0.2em] shadow-lg">
             <Sparkles size={12} className="text-emerald-400" />
             Seu Mentor Educacional
          </div>
          <h2 className="text-5xl font-black text-slate-900 tracking-tighter">
            I<span className="text-emerald-500">.</span>AM
          </h2>
          <div className="space-y-1">
            <p className="text-slate-500 text-xl font-medium max-w-lg mx-auto">
              Como posso impulsionar seu <span className="text-emerald-600 font-bold">aprendizado hoje?</span>
            </p>
          </div>
        </div>

        <div className="grid md:grid-cols-3 gap-6">
          <button onClick={() => setMode('chat')} className="group p-8 bg-white border-2 border-slate-100 rounded-[2.5rem] shadow-sm hover:shadow-2xl hover:border-emerald-500 hover:-translate-y-2 transition-all text-left space-y-5">
            <div className="w-14 h-14 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center group-hover:scale-110 group-hover:bg-emerald-600 group-hover:text-white transition-all shadow-sm">
              <MessageSquare size={28} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Diálogo Direto</h3>
              <p className="text-slate-500 text-xs leading-relaxed font-semibold mt-1">Converse com sua IA e resolva qualquer ponto do conteúdo agora.</p>
            </div>
          </button>

          <button onClick={() => setMode('summary')} className="group p-8 bg-white border-2 border-slate-100 rounded-[2.5rem] shadow-sm hover:shadow-2xl hover:border-indigo-500 hover:-translate-y-2 transition-all text-left space-y-5">
            <div className="w-14 h-14 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm">
              <BookOpen size={28} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Foco no Essencial</h3>
              <p className="text-slate-500 text-xs leading-relaxed font-semibold mt-1">Transforme textos complexos em explicações simples e diretas.</p>
            </div>
          </button>

          <button onClick={() => setMode('exam')} className="group p-8 bg-white border-2 border-slate-100 rounded-[2.5rem] shadow-sm hover:shadow-2xl hover:border-amber-500 hover:-translate-y-2 transition-all text-left space-y-5">
            <div className="w-14 h-14 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center group-hover:scale-110 group-hover:bg-amber-600 group-hover:text-white transition-all shadow-sm">
              <FileCheck size={28} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Teste de Maestria</h3>
              <p className="text-slate-500 text-xs leading-relaxed font-semibold mt-1">Valide seu conhecimento com questões criadas sob medida.</p>
            </div>
          </button>
        </div>

        {studyContext && (
          <div className={`bg-gradient-to-br from-emerald-600 via-emerald-500 to-teal-600 rounded-[3rem] text-white flex flex-col md:flex-row items-center justify-between shadow-2xl shadow-emerald-200/50 gap-8 relative overflow-hidden group ${isEmbed ? 'p-8' : 'p-12'}`}>
            <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
              <BrainCircuit size={180} />
            </div>
            <div className="space-y-4 relative z-10 text-center md:text-left">
              <div className="flex items-center gap-2 justify-center md:justify-start">
                <div className="px-3 py-1 bg-white/20 backdrop-blur-md rounded-full text-[9px] font-black uppercase tracking-widest border border-white/10">Inteligência Ativa</div>
              </div>
              <h4 className="text-3xl font-black italic max-w-sm leading-tight tracking-tight">"Aprender é o único superpoder que ninguém te tira."</h4>
            </div>
            <button onClick={() => setMode('chat')} className="bg-white text-emerald-600 px-10 py-5 rounded-2xl font-black shadow-2xl hover:scale-105 active:scale-95 transition-all z-10 whitespace-nowrap text-lg">
              Começar agora
            </button>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className={`max-w-4xl mx-auto flex flex-col bg-white border border-slate-100 overflow-hidden relative ${isEmbed ? 'h-screen rounded-none border-none' : 'h-[80vh] rounded-[2.5rem] shadow-2xl'}`}>
      {/* Header Fixo Interno Compacto */}
      <div className="px-8 py-4 bg-slate-50/50 backdrop-blur-sm border-b border-slate-100 flex items-center justify-between z-20">
        <button onClick={() => { setMode('dashboard'); setSummary(null); setExam(null); setTopicRequest(''); }} className="flex items-center gap-2 text-slate-400 hover:text-slate-900 font-black text-[9px] uppercase tracking-widest transition-all group">
          <ChevronLeft size={16} className="group-hover:-translate-x-1 transition-transform" /> Retornar
        </button>
        <div className="flex items-center gap-2 bg-white px-3 py-1 rounded-full shadow-sm border border-slate-100">
          <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
          <span className="text-[8px] font-black uppercase tracking-widest text-slate-500">
            {mode === 'chat' ? 'Modo Mentor' : mode === 'summary' ? 'Modo Síntese' : 'Modo Desafio'}
          </span>
