        <p className="text-slate-500 text-sm font-medium italic">Preparando seu material didático personalizado.</p>
      </div>
    </div>
  );

  if (mode === 'dashboard') {
    return (
      <div className={`max-w-4xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500 px-4 ${isEmbed ? 'py-4' : ''}`}>
