                 let buttonClass = "w-full p-5 text-left bg-white border-2 border-slate-100 rounded-[1.5rem] transition-all font-bold text-slate-800 flex items-center gap-4 group shadow-sm";
                 let iconClass = "w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 font-black transition-all shrink-0 text-base shadow-inner";

                 if (isShowingFeedback) {
