import { GoogleGenAI, Type } from "@google/genai";
import { IAM_SYSTEM_INSTRUCTION, EXAM_GEN_PROMPT, SUMMARY_GEN_PROMPT } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function* askIAMStream(userMessage: string, context: string, chatHistory: any[] = []) {
  const fullContext = `[CONTEXTO DE ESTUDO]\n${context}\n\nPergunta: ${userMessage}`;

  try {
    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [...chatHistory, { role: 'user', parts: [{ text: fullContext }] }],
      config: { systemInstruction: IAM_SYSTEM_INSTRUCTION, temperature: 0.7 },
    });

    for await (const chunk of responseStream) {
      if (chunk.text) {
        yield chunk.text;
      }
    }
  } catch (error) {
    console.error("Erro no stream do Gemini:", error);
    yield "Erro de conexão com o IAM. Por favor, tente novamente.";
  }
}

// Mantemos as funções não-stream para Resumo e Simulado pois são conteúdos estruturados únicos
export async function generateSummary(context: string, topic: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts: [{ text: `[CONTEXTO DE ESTUDO]\n${context}\n\n${SUMMARY_GEN_PROMPT(topic)}` }] }],
      config: { systemInstruction: IAM_SYSTEM_INSTRUCTION },
    });
    return response.text || "Não foi possível gerar o resumo.";
  } catch (error) {
    return "Erro ao gerar resumo.";
  }
}

export async function generateExam(context: string, topic: string) {
  const randomSeed = Math.random().toString(36).substring(7) + Date.now();

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts: [{ text: `[CONTEXTO DE ESTUDO]\n${context}\n\n${EXAM_GEN_PROMPT(topic, randomSeed)}` }] }],
      config: { 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.NUMBER },
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctAnswer: { type: Type.NUMBER },
              explanation: { type: Type.STRING },
            },
            required: ["id", "question", "options", "correctAnswer", "explanation"],
          },
        },
        temperature: 1.0,
      },
    });
    return JSON.parse(response.text.trim());
  } catch (error) {
    console.error("Erro ao gerar simulado:", error);
    return null;
  }
}

